    public override object parseOrder(object order, object market = null)
    {
        //
        // swap
        //     {
        //         "avgPrice": "0.00000",
        //         "clientOrderId": "abc",
        //         "cumQuote": "0",
        //         "executedQty": "0",
        //         "orderId": 1917641,
        //         "origQty": "0.40",
        //         "origType": "TRAILING_STOP_MARKET",
        //         "price": "0",
        //         "reduceOnly": false,
        //         "side": "BUY",
        //         "positionSide": "SHORT",
        //         "status": "NEW",
        //         "stopPrice": "9300",
        //         "closePosition": false,
        //         "symbol": "BTCUSDT",
        //         "time": 1579276756075,
        //         "timeInForce": "GTC",
        //         "type": "TRAILING_STOP_MARKET",
        //         "activatePrice": "9020",
        //         "priceRate": "0.3",
        //         "updateTime": 1579276756075,
        //         "workingType": "CONTRACT_PRICE",
        //         "priceProtect": false
        //     }
        //
        // spot
        //
        //   fetchOrders, fetchOpenOrders, fetchOpenOrder, fetchOrder, cancelOrder, createOrder
        //
        //        {
        //            "orderId": "417594542",
        //            "symbol": "ETHUSDT",
        //            "status": "FILLED",
        //            "clientOrderId": "web_qnvMAhOJsiVbSyu0BdKG",
        //            "price": "0",                     // value set for unfilled
        //            "avgPrice": "2351.580000",        // value zero for unfilled
        //            "origQty": "0.0054",
        //            "executedQty": "0.0054",          // value zero for unfilled
        //            "cumQuote": "12.69853200",        // value zero for unfilled
        //            "timeInForce": "GTC",
        //            "type": "MARKET",
        //            "side": "SELL",
        //            "stopPrice": "0",
        //            "origType": "MARKET",
        //            "time": "1776274219582",
        //            "updateTime": "1776274219609",
        //            "orderListId": "-1"
        //        }
        //
        object info = order;
        object marketId = this.safeString(order, "symbol");
        market = this.safeMarket(marketId, market);
        object side = this.safeStringLower(order, "side");
        object timestamp = this.safeInteger(order, "time");
        object statusId = this.safeStringUpper(order, "status");
        object rawType = this.safeStringUpper(order, "type");
        object stopPriceString = this.safeString(order, "stopPrice");
        object triggerPrice = this.parseNumber(this.omitZero(stopPriceString));
        return this.safeOrder(new Dictionary<string, object>() {
            { "info", info },
            { "id", this.safeString(order, "orderId") },
            { "clientOrderId", this.safeString(order, "clientOrderId") },
            { "symbol", this.safeSymbol(marketId, market) },
            { "timestamp", timestamp },
            { "datetime", this.iso8601(timestamp) },
            { "lastTradeTimestamp", null },
            { "lastUpdateTimestamp", this.safeInteger(order, "updateTime") },
            { "type", this.parseOrderType(rawType) },
            { "timeInForce", this.safeString(order, "timeInForce") },
            { "postOnly", null },
            { "side", side },
            { "price", this.safeString(order, "price") },
            { "triggerPrice", triggerPrice },
            { "average", this.safeString(order, "avgPrice") },
            { "cost", this.safeString(order, "cumQuote") },
            { "amount", this.safeString(order, "origQty") },
            { "filled", this.safeString(order, "executedQty") },
            { "remaining", null },
            { "status", this.parseOrderStatus(statusId) },
            { "fee", null },
            { "trades", null },
            { "reduceOnly", this.safeBool2(order, "reduceOnly", "ro") },
        }, market);
    }

